+/**
+ * [GET] /api/parser/download-template
+ * 자재주문요청서 양식 HTML 파일을 다운로드합니다.
+ */
+router.get('/parser/download-template', (req, res) => {
+    const path = require('path');
+    const templatePath = path.join(__dirname, '../templates/자재주문요청서_양식.html');
+    return res.download(templatePath, '자재주문요청서_양식.html');
+});
+
+/**
+ * [POST] /api/parser/submit-form
+ * 작성 완료된 자재 데이터를 수신하여 올빌드 대시보드(프론트엔드)로 자동 리다이렉트합니다.
+ */
+router.post('/parser/submit-form', (req, res) => {
+    const { items } = req.body;
+    
+    if (!items) {
+        return res.status(400).send('<h2>자재 데이터가 전송되지 않았습니다.</h2>');
+    }
+
+    console.log(`[API] 템플릿 폼 주문 수신 완료: ${items}`);
+
+    // 대시보드 사이트로 리다이렉트하며 쿼리 스트링으로 데이터를 실어 보냄
+    const redirectUrl = `http://localhost:5173/?source=direct-import&data=${encodeURIComponent(items)}`;
+    return res.redirect(redirectUrl);
+});
+
 module.exports = router;


